refsection.programlisting:
// computes the intergral of exp(x*x+y*y+z*z) over the
// tetrahedron (0.,0.,0.),(1.,0.,0.),(0.,1.,0.),(0.,0.,1.)

X = [0;1;0;0];
Y = [0;0;1;0];
Z = [0;0;0;1];

// function is computed by dynamically linked Fortran code

[result, err] = int3d(X, Y, Z, 'int3dex')

// Scilab function

function v = f(xyz,numfun),v=exp(xyz'*xyz), endfunction
[result, err] = int3d(X, Y, Z, f, 1, [0,100000,1.d-5,1.d-7])

// integration over a cube  -1<=x<=1;-1<=y<=1;-1<=z<=1

function v = f(xyz,numfun), v=xyz'*xyz, endfunction
[result, err] = int3d(-1,1,-1,1,-1,1, f, 1, [0,100000,1.d-5,1.d-7])

// Triple integration computing the intergral of 3*x*y^3*z^2 over 
// the integration over a cube -1<=x<=3; 1<=y<=4; 0<=z<=2
// Correct Answer is 2040

// Scilab function

function v=f(xyz,numfun)

//Note: xyz is a 3x1 matrix of the point coordinate
// x = xyz(1), y = xyz(2), z = xyz(3)
// so the code of the equation is:

   v=3*xyz(1)*xyz(2)^3*xyz(3)^2

endfunction

// int3d call

[result, err] = int3d(-1,3,1,4,0,2,f,1, [0,100000,1.d-5,1.d-7])

// Additional example with numfun = 6 versus 1 Mass Moment of Interia
// of a rectangular beam about it's mass centroid and a corner.
// Numfun > 1. This allows multiple functions to be integrated at the
// same time. The example it gave was the (components) of the inertia
// tensor (which are all integrals with the same limits, but integrals
//of different functions.)

// Scilab function

function v=f(xyz, numfun)
  x = xyz(1);
  y = xyz(2);
  z = xyz(3);
  rho = 1; // uniform density
  v = zeros(numfun,1);
  v(1) = (y^2 + z^2) * rho; // Ixx
  v(2) = (x^2 + z^2) * rho; // Iyy
  v(3) = (x^2 + y^2) * rho; // Izz
  v(4) = -x*y * rho; // Ixy
  v(5) = -x*z * rho; // Ixz
  v(6) = -y*z * rho; // Iyz
endfunction

//beam dimensions
a = 1 //length in x direction
b = 12 //length in y direction
c = 2 //length in z direction

Format = "Beam Dimensions \n length in x = %f length in y = %f length in z = %f \n \n"; mprintf(Format,a,b,c);

// int3d call

[result, err] = int3d(-a/2,a/2, -b/2,b/2, -c/2,c/2, f, 6, [0,100000,1.d-5,1.d-7]);
Ixx = result(1);
Iyy = result(2);
Izz = result(3);
Ixy = result(4);
Ixz = result(5);
Iyz = result(6);
Iyx = Ixy
Izx = Ixz
Izy = Iyz
I = [ Ixx, Ixy, Ixz; Iyx,Iyy, Iyz; Izx,Izy, Izz]
//answer is [296 0 0;0 10 0;0 0 290]
disp("Imass about mass centroid =", I)
//About one corner
[result1, err] = int3d(0,a,0,b,0,c, f, 6, [0,100000,1.d-5,1.d-7]);
Ixx = result1(1);
Iyy = result1(2);
Izz = result1(3);
Ixy = result1(4);
Ixz = result1(5);
Iyz = result1(6);
yx = Ixy
Izx = Ixz
Izy = Iyz
I = [Ixx, Ixy, Ixz; Iyx,Iyy, Iyz; Izx,Izy, Izz]
//answer is [1184 -72 -12;-72 40 -144;-12 -144 1160]
disp("Imass about a corner =", I)
